import crowdinTranslationStatus from '@/data/crowdin-translation-status.json';

/**
 * Per-route stats from data/crowdin-translation-status.json (slug = URL segment, e.g. "signal").
 */
export function getRouteTranslationStatus(slug, locale) {
  return crowdinTranslationStatus.routes?.[slug]?.[locale] ?? null;
}

/**
 * Whether to show the "machine translation not yet human-reviewed" PageNotice for this route
 * (static data from data/crowdin-translation-status.json, generated by yarn crowdin:translation-status).
 * Data is keyed by page slug (URL path), then locale: routes[slug][locale].showUnreviewedNotice
 */
export function shouldShowTranslationUnreviewedNotice(slug, locale) {
  return Boolean(crowdinTranslationStatus.routes?.[slug]?.[locale]?.showUnreviewedNotice);
}
